function binarySearch(arr, value, startPos, endPos) {
  if (startPos > endPos) return -1;
  let middleIndex = Math.floor((startPos + endPos) / 2);
  if (arr[middleIndex] === value) return middleIndex;
  if (arr[middleIndex] > value) {
    return binarySearch(arr, value, startPos, middleIndex - 1);
  }
  return binarySearch(arr, value, middleIndex + 1, endPos);
}

// Example
binarySearch([1, 3, 5, 7, 9, 11], 7, 0, 5);  // 3

At each step the algorithm checks the middle element of the current range. If it matches, the search succeeds. Otherwise it recurses on whichever half could still contain the value, halving the search space each iteration — which is why binary search runs in O(log n) time.

Example: given [2, 3, 4, 5, 7] and 3 rotations:
First rotation:  [7, 2, 3, 4, 5]
Second rotation: [5, 7, 2, 3, 4]
Third rotation:  [4, 5, 7, 2, 3]

function rotateRight(arr, rotations) {
  if (rotations === 0) return arr;
  for (let i = 0; i < rotations; i++) {
    let element = arr.pop();
    arr.unshift(element);
  }
  return arr;
}

rotateRight([2, 3, 4, 5, 7], 3);    // [4, 5, 7, 2, 3]
rotateRight([44, 1, 22, 111], 5);   // [111, 44, 1, 22]

Each iteration removes the last element and inserts it at the front, which is equivalent to a single right rotation. For very large arrays you can do this in O(n) time by computing rotations % arr.length and slicing once, rather than shifting every element on each iteration.

function isAnagram(one, two) {
  // Normalize case so the comparison is case-insensitive.
  var a = one.toLowerCase();
  var b = two.toLowerCase();
  // Sort the characters of each string and compare the results.
  a = a.split("").sort().join("");
  b = b.split("").sort().join("");
  return a === b;
}

// Example
isAnagram("listen", "silent");   // true
isAnagram("Deepak", "Aman");     // false

Two strings are anagrams when they contain exactly the same characters in some order. Sorting both and comparing them is the simplest correct approach.

const findVowels = str => {
