JavaScript provides three Object static methods that return arrays:

let obj = { id: "1", name: "user22", age: "26", work: "programmer" };

// Just the keys
Object.keys(obj);
// ["id", "name", "age", "work"]

// Just the values
Object.values(obj);
// ["1", "user22", "26", "programmer"]

// Both, as [key, value] pairs
Object.entries(obj);
// [["id", "1"], ["name", "user22"], ["age", "26"], ["work", "programmer"]]

Object.entries pairs nicely with Map (new Map(Object.entries(obj))) and with for...of loops for iterating an object's own enumerable properties.
